{"file_path": "/home/abdelah/Documents/eaglepoint/TASK-31/repo/src/main/resources/static/css/custom.css", "content": "/* Retail Campaign Governance — custom design system
   Color palette and tokens defined in CLAUDE.md.
*/

:root {
  --sidebar-bg: #1e293b;
  --sidebar-bg-hover: #334155;
  --sidebar-text: #cbd5e1;
  --sidebar-text-active: #ffffff;
  --primary: #3b82f6;
  --primary-dark: #2563eb;
  --success: #22c55e;
  --warning: #f59e0b;
  --danger: #ef4444;
  --info: #06b6d4;
  --bg: #f8fafc;
  --card-bg: #ffffff;
  --card-shadow: 0 1px 3px 0 rgba(0,0,0,0.06), 0 1px 2px 0 rgba(0,0,0,0.04);
  --card-shadow-lg: 0 4px 12px -2px rgba(0,0,0,0.08), 0 2px 6px -2px rgba(0,0,0,0.04);
  --border: #e2e8f0;
  --text: #0f172a;
  --text-muted: #64748b;
  --radius: 12px;
  --radius-sm: 8px;
  --space: 8px;
  --sidebar-width: 240px;
  --header-height: 64px;
}

* { box-sizing: border-box; }

html, body {
  margin: 0;
  padding: 0;
  font-family: 'Inter', -apple-system, BlinkMacSystemFont, 'Segoe UI', system-ui, sans-serif;
  font-size: 14px;
  font-weight: 400;
  line-height: 1.6;
  color: var(--text);
  background-color: var(--bg);
  -webkit-font-smoothing: antialiased;
}

h1, h2, h3, h4, h5, h6 {
  font-weight: 600;
  color: var(--text);
  margin-top: 0;
}

a { color: var(--primary); text-decoration: none; }
a:hover { color: var(--primary-dark); text-decoration: underline; }

/* ===== Sidebar Navigation ===== */
.app-sidebar {
  position: fixed;
  top: 0;
  left: 0;
  bottom: 0;
  width: var(--sidebar-width);
  background-color: var(--sidebar-bg);
  color: var(--sidebar-text);
  display: flex;
  flex-direction: column;
  z-index: 1000;
  overflow-y: auto;
}

.app-sidebar .brand {
  padding: 24px 20px;
  border-bottom: 1px solid rgba(255,255,255,0.06);
}
.app-sidebar .brand h1 {
  color: #fff;
  font-size: 17px;
  font-weight: 600;
  margin: 0;
  letter-spacing: -0.01em;
}
.app-sidebar .brand small {
  color: #94a3b8;
  font-size: 11px;
  text-transform: uppercase;
  letter-spacing: 0.05em;
}

.app-sidebar nav { padding: 12px 0; flex: 1; }
.app-sidebar nav .nav-section {
  padding: 12px 20px 6px;
  font-size: 11px;
  color: #64748b;
  text-transform: uppercase;
  letter-spacing: 0.06em;
  font-weight: 600;
}
.app-sidebar nav a {
  display: flex;
  align-items: center;
  gap: 12px;
  padding: 10px 20px;
  color: var(--sidebar-text);
  text-decoration: none;
  font-size: 14px;
  font-weight: 500;
  transition: background 0.15s;
  border-left: 3px solid transparent;
}
.app-sidebar nav a:hover {
  background-color: var(--sidebar-bg-hover);
  color: var(--sidebar-text-active);
  text-decoration: none;
}
.app-sidebar nav a.active {
  background-color: var(--sidebar-bg-hover);
  color: var(--sidebar-text-active);
  border-left-color: var(--primary);
}
.app-sidebar nav a i { font-size: 16px; width: 18px; text-align: center; }

/* ===== Main Content Area ===== */
.app-main {
  margin-left: var(--sidebar-width);
  min-height: 100vh;
  display: flex;
  flex-direction: column;
}

.app-header {
  height: var(--header-height);
  background: var(--card-bg);
  border-bottom: 1px solid var(--border);
  padding: 0 32px;
  display: flex;
  align-items: center;
  justify-content: space-between;
  position: sticky;
  top: 0;
  z-index: 100;
}
.app-header .breadcrumbs {
  font-size: 13px;
  color: var(--text-muted);
}
.app-header .breadcrumbs strong { color: var(--text); font-weight: 600; }
.app-header .user-info {
  display: flex;
  align-items: center;
  gap: 14px;
  font-size: 13px;
}

.app-content {
  padding: 32px;
  flex: 1;
}

/* ===== Cards ===== */
.card {
  background: var(--card-bg);
  border: 1px solid var(--border);
  border-radius: var(--radius);
  box-shadow: var(--card-shadow);
}
.card .card-header {
  background: transparent;
  border-bottom: 1px solid var(--border);
  padding: 18px 24px;
  font-weight: 600;
}
.card .card-body { padding: 24px; }
.card .card-footer { padding: 16px 24px; background: #f8fafc; border-top: 1px solid var(--border); }

/* ===== Role Badges ===== */
.role-badge {
  display: inline-block;
  padding: 3px 10px;
  border-radius: 999px;
  font-size: 11px;
  font-weight: 600;
  text-transform: uppercase;
  letter-spacing: 0.04em;
}
.role-badge.role-admin { background: #ede9fe; color: #6b21a8; }
.role-badge.role-reviewer { background: #dbeafe; color: #1e40af; }
.role-badge.role-operations { background: #dcfce7; color: #166534; }
.role-badge.role-finance { background: #fef3c7; color: #92400e; }
.role-badge.role-customer-service { background: #f1f5f9; color: #475569; }

/* ===== Status Badges ===== */
.status-badge {
  display: inline-block;
  padding: 3px 10px;
  border-radius: 6px;
  font-size: 11px;
  font-weight: 600;
  text-transform: uppercase;
  letter-spacing: 0.04em;
}
.status-draft { background: #f1f5f9; color: #475569; }
.status-pending { background: #fef3c7; color: #92400e; }
.status-approved { background: #dcfce7; color: #166534; }
.status-active { background: #dcfce7; color: #166534; }
.status-rejected { background: #fee2e2; color: #991b1b; }
.status-expired { background: #f1f5f9; color: #475569; }
.status-low { background: #dcfce7; color: #166534; }
.status-medium { background: #fef3c7; color: #92400e; }
.status-high { background: #fee2e2; color: #991b1b; }
.status-critical { background: #fecaca; color: #7f1d1d; }

/* ===== Buttons ===== */
.btn { font-weight: 500; border-radius: var(--radius-sm); padding: 8px 16px; font-size: 14px; }
.btn-primary { background-color: var(--primary); border-color: var(--primary); }
.btn-primary:hover { background-color: var(--primary-dark); border-color: var(--primary-dark); }
.btn[disabled],
.btn.disabled,
button[disabled] {
  cursor: not-allowed !important;
  opacity: 0.55;
}

/* ===== Forms ===== */
.form-label { font-weight: 500; font-size: 13px; color: var(--text); margin-bottom: 6px; }
.form-control, .form-select {
  border: 1px solid var(--border);
  border-radius: var(--radius-sm);
  padding: 9px 12px;
  font-size: 14px;
}
.form-control:focus, .form-select:focus {
  border-color: var(--primary);
  box-shadow: 0 0 0 3px rgba(59,130,246,0.12);
}
.form-text { font-size: 12px; color: var(--text-muted); }
.invalid-feedback { font-size: 12px; }
.is-invalid { border-color: var(--danger) !important; }
.is-valid { border-color: var(--success) !important; }
.field-validation-success { color: var(--success); font-size: 12px; }
.field-validation-error { color: var(--danger); font-size: 12px; }

/* ===== KPI Cards ===== */
.kpi-card {
  background: var(--card-bg);
  border: 1px solid var(--border);
  border-radius: var(--radius);
  padding: 20px;
  box-shadow: var(--card-shadow);
}
.kpi-card .kpi-label {
  font-size: 12px;
  font-weight: 600;
  color: var(--text-muted);
  text-transform: uppercase;
  letter-spacing: 0.05em;
  margin-bottom: 8px;
}
.kpi-card .kpi-value {
  font-size: 28px;
  font-weight: 700;
  color: var(--text);
  line-height: 1.1;
}
.kpi-card .kpi-trend {
  font-size: 12px;
  margin-top: 8px;
  color: var(--text-muted);
}

/* ===== Empty States ===== */
.empty-state {
  text-align: center;
  padding: 60px 20px;
  background: var(--card-bg);
  border: 1px dashed var(--border);
  border-radius: var(--radius);
}
.empty-state .empty-icon {
  font-size: 48px;
  color: #cbd5e1;
  margin-bottom: 16px;
}
.empty-state h3 {
  font-size: 16px;
  font-weight: 600;
  color: var(--text);
}
.empty-state p {
  color: var(--text-muted);
  font-size: 14px;
  margin-bottom: 20px;
}

/* ===== Loading Spinner ===== */
.htmx-indicator {
  display: none;
  width: 18px;
  height: 18px;
  border: 2px solid #e2e8f0;
  border-top-color: var(--primary);
  border-radius: 50%;
  animation: spin 0.7s linear infinite;
}
.htmx-request .htmx-indicator,
.htmx-request.htmx-indicator { display: inline-block; }
@keyframes spin { to { transform: rotate(360deg); } }

/* ===== Tables ===== */
.table { background: var(--card-bg); }
.table thead th {
  font-size: 11px;
  font-weight: 600;
  text-transform: uppercase;
  letter-spacing: 0.04em;
  color: var(--text-muted);
  border-bottom: 1px solid var(--border);
  padding: 12px 16px;
}
.table tbody td { padding: 14px 16px; border-bottom: 1px solid var(--border); vertical-align: middle; }
.table tbody tr:hover { background: #f8fafc; }

/* ===== Login Page ===== */
.login-shell {
  min-height: 100vh;
  display: flex;
  align-items: center;
  justify-content: center;
  background: linear-gradient(135deg, #1e293b 0%, #334155 100%);
  padding: 20px;
}
.login-card {
  width: 100%;
  max-width: 420px;
  background: #fff;
  border-radius: var(--radius);
  box-shadow: 0 20px 60px -10px rgba(0,0,0,0.4);
  padding: 40px;
}
.login-card h1 {
  font-size: 22px;
  font-weight: 700;
  margin-bottom: 4px;
}
.login-card .login-subtitle {
  color: var(--text-muted);
  font-size: 13px;
  margin-bottom: 28px;
}

/* ===== Receipt Preview ===== */
.receipt-preview {
  font-family: 'Courier New', monospace;
  background: #f8fafc;
  border: 1px dashed #94a3b8;
  border-radius: var(--radius-sm);
  padding: 20px;
  font-size: 13px;
  white-space: pre-wrap;
  color: #1e293b;
}

/* ===== Drag-drop upload zone ===== */
.upload-zone {
  border: 2px dashed var(--border);
  border-radius: var(--radius);
  padding: 50px 20px;
  text-align: center;
  background: #f8fafc;
  cursor: pointer;
  transition: all 0.15s;
}
.upload-zone:hover, .upload-zone.dragover {
  border-color: var(--primary);
  background: #eff6ff;
}
.upload-zone .upload-icon {
  font-size: 40px;
  color: var(--primary);
  margin-bottom: 12px;
}

/* ===== Why-blocked tooltip styling ===== */
[data-blocked-reason] {
  position: relative;
  cursor: not-allowed;
}

/* ===== Flash messages ===== */
.flash-area .alert { border-radius: var(--radius-sm); border: none; }
"}

