.field-validation-error { color: var(--danger); font-size: 12px; }

/* ===== KPI Cards ===== */
.kpi-card {
  background: var(--card-bg);
  border: 1px solid var(--border);
  border-radius: var(--radius);
  padding: 20px;
  box-shadow: var(--card-shadow);
}
.kpi-card .kpi-label {
  font-size: 12px;
  font-weight: 600;
  color: var(--text-muted);
  text-transform: uppercase;
  letter-spacing: 0.05em;
  margin-bottom: 8px;
}
.kpi-card .kpi-value {
  font-size: 28px;
  font-weight: 700;
  color: var(--text);
  line-height: 1.1;
}
.kpi-card .kpi-trend {
  font-size: 12px;
  margin-top: 8px;
  color: var(--text-muted);
}

/* ===== Empty States ===== */
.empty-state {
  text-align: center;
  padding: 60px 20px;
  background: var(--card-bg);
  border: 1px dashed var(--border);
  border-radius: var(--radius);
}
.empty-state .empty-icon {
  font-size: 48px;
  color: #cbd5e1;
  margin-bottom: 16px;
}
.empty-state h3 {
  font-size: 16px;
  font-weight: 600;
  color: var(--text);
}
.empty-state p {
  color: var(--text-muted);
  font-size: 14px;
  margin-bottom: 20px;
}

/* ===== Loading Spinner ===== */
.htmx-indicator {
  display: none;
  width: 18px;
  height: 18px;
  border: 2px solid #e2e8f0;
  border-top-color: var(--primary);
  border-radius: 50%;
  animation: spin 0.7s linear infinite;
}
.htmx-request .htmx-indicator,
.htmx-request.htmx-indicator { display: inline-block; }
@keyframes spin { to { transform: rotate(360deg); } }

/* ===== Tables ===== */
.table { background: var(--card-bg); }
.table thead th {
  font-size: 11px;
  font-weight: 600;
  text-transform: uppercase;
  letter-spacing: 0.04em;
  color: var(--text-muted);
  border-bottom: 1px solid var(--border);
  padding: 12px 16px;
}
.table tbody td { padding: 14px 16px; border-bottom: 1px solid var(--border); vertical-align: middle; }
.table tbody tr:hover { background: #f8fafc; }

/* ===== Login Page ===== */
.login-shell {
  min-height: 100vh;
  display: flex;
  align-items: center;
  justify-content: center;
  background: linear-gradient(135deg, #1e293b 0%, #334155 100%);
  padding: 20px;
}
.login-card {
  width: 100%;
  max-width: 420px;
  background: #fff;
  border-radius: var(--radius);
  box-shadow: 0 20px 60px -10px rgba(0,0,0,0.4);
  padding: 40px;
}
.login-card h1 {
  font-size: 22px;
  font-weight: 700;
  margin-bottom: 4px;
}
.login-card .login-subtitle {
  color: var(--text-muted);
  font-size: 13px;
  margin-bottom: 28px;
}

/* ===== Receipt Preview ===== */
.receipt-preview {
  font-family: 'Courier New', monospace;
  background: #f8fafc;
  border: 1px dashed #94a3b8;
  border-radius: var(--radius-sm);
  padding: 20px;
  font-size: 13px;
  white-space: pre-wrap;
  color: #1e293b;
}

/* ===== Drag-drop upload zone ===== */
.upload-zone {
  border: 2px dashed var(--border);
  border-radius: var(--radius);
  padding: 50px 20px;
  text-align: center;
  background: #f8fafc;
  cursor: pointer;
  transition: all 0.15s;
}
.upload-zone:hover, .upload-zone.dragover {
  border-color: var(--primary);
  background: #eff6ff;
}
.upload-zone .upload-icon {
  font-size: 40px;
  color: var(--primary);
  margin-bottom: 12px;
}

/* ===== Why-blocked tooltip styling ===== */
[data-blocked-reason] {
  position: relative;
  cursor: not-allowed;
}

/* ===== Flash messages ===== */
.flash-area .alert { border-radius: var(--radius-sm); border: none; }
"}

