            if (lk.startsWith("utm_") || lk.equals("fbclid") || lk.equals("gclid") || lk.startsWith("mc_")) {
                continue;
            }
            kept.put(key, val);
        }
        if (kept.isEmpty()) return "";
        StringBuilder out = new StringBuilder();
        kept.forEach((k, v) -> {
            if (out.length() > 0) out.append("&");
            out.append(k);
            if (!v.isEmpty()) out.append("=").append(v);
        });
        return out.toString();
    }
}
