            if (!b.containsKey(key)) diff.put(key, new Object[]{null, a.get(key)});
        }
        return diff;
    }

    private String toJson(Object value) {
        try {
            return objectMapper.writeValueAsString(value);
        } catch (Exception e) {
            return "{}";
