19	/**
20	 * Role-aware dashboard router. Each role has its own landing page populated entirely from
21	 * the database via repositories — there is NO hardcoded data in any template.
22	 *
23	 * The /dashboard endpoint inspects the current authentication and forwards the user to
24	 * their primary dashboard. The role-specific endpoints below are also reachable directly
25	 * from the sidebar.
26	 */
27	@Controller
28	@RequiredArgsConstructor
29	public class DashboardController {
30	
31	    private final CampaignRepository campaignRepository;
32	    private final ApprovalQueueRepository approvalQueueRepository;
33	    private final UserRepository userRepository;
34	    private final AnomalyAlertRepository anomalyAlertRepository;
35	    private final BackupRecordRepository backupRecordRepository;
36	    private final ContentItemRepository contentItemRepository;
37	
38	    /** Generic post-login router — forwards to the per-role landing page. */
39	    @GetMapping("/dashboard")
40	    public String dashboard(Authentication authentication) {
41	        String role = authentication.getAuthorities().stream()
42	                .map(GrantedAuthority::getAuthority)
43	                .findFirst()
44	                .orElse("ROLE_USER");
45	        return switch (role) {
46	            case "ROLE_ADMIN"            -> "redirect:/admin/dashboard";
47	            case "ROLE_REVIEWER"         -> "redirect:/approval/queue";
48	            case "ROLE_FINANCE"          -> "redirect:/analytics/dashboard";
49	            case "ROLE_OPERATIONS"       -> "redirect:/campaigns";
50	            case "ROLE_CUSTOMER_SERVICE" -> "redirect:/campaigns";
51	            default                      -> "redirect:/login";
52	        };
53	    }
54	
55	    /** ADMIN dashboard — full operational summary, populated from real DB queries. */
56	    @GetMapping("/admin/dashboard")
57	    @PreAuthorize("hasRole('ADMIN')")
58	    public String adminDashboard(Model model) {
59	        model.addAttribute("breadcrumb", "Admin Dashboard");
60	        model.addAttribute("totalUsers", userRepository.count());
61	        model.addAttribute("activeUsers", userRepository.countByActiveTrue());
62	        model.addAttribute("activeCampaigns", campaignRepository.countByStatusAndDeletedAtIsNull(CampaignStatus.ACTIVE));
63	        model.addAttribute("draftCampaigns", campaignRepository.countByStatusAndDeletedAtIsNull(CampaignStatus.DRAFT));
64	        model.addAttribute("pendingApprovals", approvalQueueRepository.countByStatus(ApprovalStatus.PENDING));
65	        model.addAttribute("unacknowledgedAlerts", anomalyAlertRepository.countByAcknowledgedAtIsNull());
66	        model.addAttribute("contentItemCount", contentItemRepository.count());
67	        model.addAttribute("lastBackup",
68	                backupRecordRepository.findTop1ByStatusOrderByCreatedAtDesc(com.meridian.retail.entity.BackupStatus.COMPLETE)
69	                        .orElse(null));
70	        return "dashboard/admin";
71	    }
72	}
