{"file_path": "/home/abdelah/Documents/eaglepoint/TASK-31/repo/src/test/java/com/meridian/retail/integration/AbstractIntegrationTest.java", "content": "package com.meridian.retail.integration;

import org.springframework.boot.test.context.SpringBootTest;
import org.springframework.test.context.ActiveProfiles;
import org.springframework.test.context.DynamicPropertyRegistry;
import org.springframework.test.context.DynamicPropertySource;
import org.testcontainers.containers.MySQLContainer;
import org.testcontainers.junit.jupiter.Container;
import org.testcontainers.junit.jupiter.Testcontainers;

/**
 * Base class for all integration tests.
 *
 * Two modes:
 *   1. LOCAL DEV — Testcontainers spins up a fresh MySQL 8 container per JVM run.
 *   2. INSIDE docker-compose.test.yml — the {@code mysql-test} service is already running on
 *      the same docker network. We detect this via the IT_DATASOURCE_URL environment variable
 *      and skip the Testcontainer to avoid the docker-in-docker networking issues that
 *      Testcontainers' "host.docker.internal" port mapping cannot reach from inside another
 *      container. The test runner image sets IT_DATASOURCE_URL=jdbc:mysql://mysql-test:3306/retail_campaign_test
 *      so the tests connect directly to the sibling MySQL container.
 *
 * In either mode Flyway runs the real migrations and ddl-auto is forced to "validate".
 */
@SpringBootTest
@ActiveProfiles("test")
@Testcontainers
public abstract class AbstractIntegrationTest {

    private static final String EXTERNAL_URL = System.getenv("IT_DATASOURCE_URL");
    private static final boolean USE_EXTERNAL = EXTERNAL_URL != null && !EXTERNAL_URL.isBlank();

    @Container
    @SuppressWarnings("resource") // container is reused for the JVM lifetime
    static final MySQLContainer<?> MYSQL = USE_EXTERNAL
            ? null
            : new MySQLContainer<>("mysql:8.0")
                    .withDatabaseName("retail_campaign_test")
                    .withUsername("retail_user")
                    .withPassword("retail_pass");

    @DynamicPropertySource
    static void registerProps(DynamicPropertyRegistry r) {
        if (USE_EXTERNAL) {
            // Inside docker-compose.test.yml — connect to the sibling mysql-test service.
            r.add("spring.datasource.url", () -> EXTERNAL_URL);
            r.add("spring.datasource.username",
                    () -> System.getenv().getOrDefault("IT_DATASOURCE_USERNAME", "retail_user"));
            r.add("spring.datasource.password",
                    () -> System.getenv().getOrDefault("IT_DATASOURCE_PASSWORD", "retail_pass"));
        } else {
            // Local dev — use the Testcontainers MySQL.
            if (!MYSQL.isRunning()) MYSQL.start();
            r.add("spring.datasource.url", MYSQL::getJdbcUrl);
            r.add("spring.datasource.username", MYSQL::getUsername);
            r.add("spring.datasource.password", MYSQL::getPassword);
        }
        r.add("spring.datasource.driver-class-name", () -> "com.mysql.cj.jdbc.Driver");
        r.add("spring.flyway.enabled", () -> "true");
        r.add("spring.jpa.hibernate.ddl-auto", () -> "validate");
    }
}
"}

